def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            if ratio < 0.05 * j:
                score += (10 - j) * np.exp(-ratio * j * 2) + np.sin(ratio * np.pi * j)
            elif 0.05 * j <= ratio < 0.4:
                score += (j ** 3) * np.cos(ratio * np.pi * j / 2) - np.log1p(ratio * j)
            else:
                score += np.sqrt(ratio * j) * np.tanh(j / (ratio + 0.1))
        if capacity - item < 0.03 * capacity:
            score *= 2.5
            for m in range(1, 5):
                if (capacity - item) / capacity < 0.01 * m:
                    score += m * np.exp(-m * ratio)
        elif capacity - item < 0.15 * capacity:
            score *= 1.5
            for n in range(1, 3):
                score += n * np.sin(ratio * np.pi * n) * np.log1p(capacity - item)
        else:
            for p in range(1, 6):
                if (capacity - item) / capacity > 0.25 * p:
                    score += p * np.sqrt(item / (capacity + 1e-5)) * np.cos(ratio * np.pi * p)
        if item > 0.7 * capacity:
            score += np.tanh(item / capacity) * 7
            if ratio > 0.9:
                score += np.exp(ratio * 5) / (capacity + 1)
        if score < 0:
            score = abs(score) * 0.3 + 1
        if np.isnan(score) or np.isinf(score):
            priorities[i] = np.inf
        else:
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    return priorities
